// Validate required fields and normalise the webhook payload.
// Supports both flat and nested body (n8n wraps POST body under $json).
const body = $input.first().json;
const contact = body.contact || {};
const projectState = body.projectState || {};
const estimate = body.estimate || {};

if (!contact.name || contact.name.trim() === '') {
  throw new Error('Validation failed: contact.name is required');
}
if (!contact.phone || contact.phone.trim() === '') {
  throw new Error('Validation failed: contact.phone is required');
}

const features = projectState.features || [];

return [{
  json: {
    name:          contact.name.trim(),
    email:         (contact.email || '').trim(),
    phone:         contact.phone.trim(),
    notes:         (contact.notes || '').trim(),
    project_type:  projectState.project_type  || '',
    bathroom_size: projectState.bathroom_size || '',
    shower_tub:    projectState.shower_tub    || '',
    tile_level:    projectState.tile_level    || '',
    fixtures:      projectState.fixtures      || '',
    features:      Array.isArray(features) ? features.join(',') : String(features),
    timeline:      projectState.timeline      || '',
    estimate_low:  Number(estimate.low)       || 0,
    estimate_high: Number(estimate.high)      || 0,
    source:        body.source                || 'website_calculator'
  }
}];

// Merge all extracted data + JT IDs into a flat record for Postgres INSERT.
const lead       = $('Extract Lead').item.json;
const accountRes = $('JT: Create Account').item.json;
const jobRes     = $('JT: Create Job').item.json;

return [{
  json: {
    name:          lead.name,
    email:         lead.email,
    phone:         lead.phone,
    notes:         lead.notes,
    project_type:  lead.project_type,
    bathroom_size: lead.bathroom_size,
    shower_tub:    lead.shower_tub,
    tile_level:    lead.tile_level,
    fixtures:      lead.fixtures,
    features:      lead.features,
    timeline:      lead.timeline,
    estimate_low:  lead.estimate_low,
    estimate_high: lead.estimate_high,
    source:        lead.source,
    jt_account_id: (accountRes.data || {}).id || '',
    jt_job_id:     (jobRes.data     || {}).id || '',
    status:        'new'
  }
}];
